            Product.objects.create(name="Mouse", price=29.99),
            Product.objects.create(name="Keyboard", price=79.99),
        ]

# tests/integration/test_checkout.py
@pytest.mark.django_db
def test_checkout_with_sample_products(user, sample_products):
    """Fast test using pre-created session-scoped products."""
    cart = Cart.objects.create(user=user)
    for product in sample_products:
        cart.items.create(product=product, quantity=1)
    total = cart.calculate_total()
    assert total == sum(p.price for p in sample_products)

# tests/factories/orders.py
import factory
from decimal import Decimal
from apps.orders.models import Order, OrderItem
from apps.products.models import Product

class ProductFactory(factory.django.DjangoModelFactory):
    class Meta:
        model = Product

    name = factory.Faker("word")
    price = factory.fuzzy.FuzzyDecimal(10.00, 100.00, precision=2)
    stock = factory.fuzzy.FuzzyInteger(1, 100)
    is_active = True

class OrderFactory(factory.django.DjangoModelFactory):
    class Meta:
        model = Order

    user = factory.SubFactory(UserFactory)
    status = "pending"
    shipping_address = factory.Faker("address")

    @factory.post_generation
    def items(self, create, extracted, **kwargs):
        if not create:
            return
        if extracted:
            for item in extracted:
                OrderItemFactory(order=self, **item)

class OrderItemFactory(factory.django.DjangoModelFactory):
    class Meta:
        model = OrderItem

    order = factory.SubFactory(OrderFactory)
    product = factory.SubFactory(ProductFactory)
    quantity = factory.fuzzy.FuzzyInteger(1, 5)
    unit_price = factory.LazyAttribute(lambda o: o.product.price)

